<template>
    <div>
        Hello<br>
        <button @click="searchTerm()">https://jsonplaceholder.typicode.com/posts</button><br>
        날짜(yyyymmdd)<input type="text" name="targetDt"> <button @click="moveRank()">getMoveRank</button><br>
        <button @click="clear()">비우기</button><br>
        <div id="dummyArea"></div>
    </div>
</template>

<script>

    import { yyyymmdd } from '../assets/js/util.js';

    export default {
        name: "Hello",
        created() {
        },
        methods: {
            searchTerm: function () {
                // this.axios.get("http://localhost/getBoardList")
                this.axios.get(`https://jsonplaceholder.typicode.com/posts`)
                    .then((data) => {
                        _.forEach(data.data, (item) => {
                            $("#dummyArea").append(item.title + "<br>");
                        });
                    });
            },
            moveRank: function () {
                let targetDt = $("input[name=targetDt]").val();
                let params = {
                    targetDt : targetDt || yyyymmdd()
                };
                console.log(targetDt)
                // this.axios.get(`http://localhost/getMoveRankList?${$.param(params)}`)
                this.axios.get(`http://www.kobis.or.kr/kobisopenapi/webservice/rest/boxoffice/searchDailyBoxOfficeList.json?key=f433c1c717bf977fe73d40e81d5d8a10&targetDt=${targetDt || yyyymmdd()}`)
                    .then((data) => {
                        let result = data.data;
                        console.log(result);
                        console.log(result.boxOfficeResult);

                        _.forEach(result.boxOfficeResult.dailyBoxOfficeList, (item) => {
                            console.log(item);
                            let html = "";

                            html += `${item.rank}위`;
                            html += ` | 제목 : ${item.movieNm}`;
                            html += ` | 개봉날짜 : ${item.openDt}`;

                            html += "<br>";
                            $("#dummyArea").append(html);
                        });

                    });
            },
            clear: function () {
                $("#dummyArea").empty();
            }
        }
    }
</script>
<!--
boxofficeType	문자열	박스오피스 종류를 출력합니다.
showRange	문자열	박스오피스 조회 일자를 출력합니다.
rnum	문자열	순번을 출력합니다.
rank	문자열	해당일자의 박스오피스 순위를 출력합니다.
rankInten	문자열	전일대비 순위의 증감분을 출력합니다.
rankOldAndNew	문자열	랭킹에 신규진입여부를 출력합니다.
“OLD” : 기존 , “NEW” : 신규
movieCd	문자열	영화의 대표코드를 출력합니다.
movieNm	문자열	영화명(국문)을 출력합니다.
openDt	문자열	영화의 개봉일을 출력합니다.
salesAmt	문자열	해당일의 매출액을 출력합니다.
salesShare	문자열	해당일자 상영작의 매출총액 대비 해당 영화의 매출비율을 출력합니다.
salesInten	문자열	전일 대비 매출액 증감분을 출력합니다.
salesChange	문자열	전일 대비 매출액 증감 비율을 출력합니다.
salesAcc	문자열	누적매출액을 출력합니다.
audiCnt	문자열	해당일의 관객수를 출력합니다.
audiInten	문자열	전일 대비 관객수 증감분을 출력합니다.
audiChange	문자열	전일 대비 관객수 증감 비율을 출력합니다.
audiAcc	문자열	누적관객수를 출력합니다.
scrnCnt	문자열	해당일자에 상영한 스크린수를 출력합니다.
showCnt	문자열	해당일자에 상영된 횟수를 출력합니다.
-->
